<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Monitor.php'; $db=Database::getInstance();$pe=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='public_page_enabled'")??'1';if($pe!=='1'){http_response_code(404);die('Public status page disabled.');} $sn=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='site_name'")??'Status Monitor';$sd=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='site_description'")??'';$sites=$db->fetchAll("SELECT * FROM `sites` WHERE is_active=1 ORDER BY display_order ASC, name ASC");$cs=Monitor::getCurrentStatus();$summary=Monitor::getSummary();$hd=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='history_days'")??90);$ci=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='check_interval'")??300);$dates=[];for($i=$hd-1;$i>=0;$i--)$dates[]=date('Y-m-d',strtotime("-$i days"));$tx=['ok'=>'Õ£¿þ║┐','error'=>'þª╗þ║┐','warning'=>'Þ¡ªÕæè','timeout'=>'ÞÂàµùÂ','unknown'=>'µ£¬þƒÑ']; $siteData=[];foreach($sites as $s){$sid=(int)$s['id'];$siteData[$sid]=['st'=>$cs[$sid]??['status'=>'unknown','http_code'=>null,'response_time'=>0,'error_message'=>'No data','checked_at'=>null,'ssl'=>null,'dns'=>null],'ut'=>Monitor::getUptimeStats($sid),'tr'=>Monitor::getResponseTrend($sid,$hd)];}?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><meta name="description" content="<?php echo e($sd);?>"><title><?php echo e($sn);?> - µ£ìÕèíþèÂµÇüþøæµÄº</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/public.css" rel="stylesheet"><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script></head><body><div class="container"><header><div class="header-content"><div class="header-left"><h1><span class="status-dot active"></span><?php echo e($sn);?></h1><p class="header-desc"><?php echo e($sd);?></p></div><div class="header-right"><div class="last-updated"><span class="material-icons">schedule</span><span>µ£ÇÕÉÄµø┤µû░: <?php echo $summary['last_checked']?date('Y-m-d H:i:s',strtotime($summary['last_checked'])):'N/A';?></span></div><div class="system-status"><span class="status-indicator active"></span><span>þ│╗þ╗ƒÞ┐ÉÞíîõ©¡</span></div></div></div></header><div class="summary-stats"><div class="summary-card"><div class="card-icon"><span class="material-icons">dns</span></div><div class="card-content"><span class="summary-value"><?php echo (int)$summary['total_sites'];?></span><span class="summary-label">þøæµÄºþ½Öþé╣</span></div></div><div class="summary-card online"><div class="card-icon"><span class="material-icons">check_circle</span></div><div class="card-content"><span class="summary-value"><?php echo (int)$summary['online_sites'];?></span><span class="summary-label">Õ£¿þ║┐</span></div></div><div class="summary-card offline"><div class="card-icon"><span class="material-icons">error</span></div><div class="card-content"><span class="summary-value"><?php echo (int)$summary['offline_sites'];?></span><span class="summary-label">þª╗þ║┐</span></div></div><div class="summary-card"><div class="card-icon"><span class="material-icons">speed</span></div><div class="card-content"><span class="summary-value"><?php echo (int)$summary['avg_response'];?> ms</span><span class="summary-label">Õ╣│ÕØçÕôìÕ║ö</span></div></div></div><div class="status-grid"><?php foreach($sites as $s):$sid=(int)$s['id'];$d=$siteData[$sid];$st=$d['st'];$ut=$d['ut'];$tr=$d['tr'];$cid='c'.$sid;?><div class="status-card <?php echo e($st['status']??'unknown');?>"><div class="status-header"><div class="site-info"><h3><?php echo e($s['name']);?></h3><a href="<?php echo e($s['url']);?>" target="_blank" rel="noopener" class="site-url"><?php echo e(parse_url($s['url'],PHP_URL_HOST));?> <span class="material-icons">open_in_new</span></a></div><div class="status-badge <?php echo e($st['status']??'unknown');?>"><?php echo e($tx[$st['status']]??'µ£¬þƒÑ');?></div></div><div class="status-details"><div class="detail-row"><span class="detail-label"><span class="material-icons">http</span> þèÂµÇüþáü</span><span class="detail-value"><?php echo e($st['http_code']!==null?(string)$st['http_code']:'N/A');?></span></div><div class="detail-row"><span class="detail-label"><span class="material-icons">timer</span> ÕôìÕ║öµùÂÚù┤</span><span class="detail-value"><?php echo (int)($st['response_time']??0);?> ms</span></div><?php if(!empty($st['ssl'])):?><div class="detail-row"><span class="detail-label"><span class="material-icons">lock</span> SSLÞ»üõ╣ª</span><span class="detail-value <?php echo $st['ssl']['valid']?'text-success':'text-danger';?>"><?php if($st['ssl']['valid']):?>Õë®õ¢Ö <?php echo (int)$st['ssl']['days_remaining'];?> Õñ® (<?php echo e($st['ssl']['expires']??'');?>)<?php else:?>ÕÀ▓Þ┐çµ£ƒ/µùáµòê<?php if(!empty($st['ssl']['issuer'])):?><?php endif;?><?php endif;?></span></div><?php endif;?><?php if(!empty($st['dns'])):?><div class="detail-row"><span class="detail-label"><span class="material-icons">dns</span> DNSÞºúµ×É</span><span class="detail-value <?php echo $st['dns']['resolved']?'text-success':'text-danger';?>"><?php echo $st['dns']['resolved']?'µêÉÕèƒ':'Õñ▒Þ┤Ñ';?><?php echo !empty($st['dns']['a_records'])?' ('.e(implode(', ',(array)$st['dns']['a_records'])).')':'';?></span></div><?php endif;?><?php if(!empty($st['error_message'])):?><div class="detail-row"><span class="detail-label"><span class="material-icons">info</span> þèÂµÇüõ┐íµü»</span><span class="detail-value text-danger"><?php echo e($st['error_message']);?></span></div><?php endif;?><div class="detail-row"><span class="detail-label"><span class="material-icons">access_time</span> µ£ÇÕÉÄµúÇµÁï</span><span class="detail-value"><?php echo !empty($st['checked_at'])?e($st['checked_at']):'õ╗Äµ£¬µúÇµÁï';?></span></div></div><div class="uptime-stats"><h4><span class="material-icons">bar_chart</span> ÕÅ»þö¿þÄçþ╗ƒÞ«í</h4><?php foreach(['daily'=>'õ╗èµùÑ','weekly'=>'µ£¼Õæ¿','monthly'=>'µ£¼µ£ê','all_time'=>'ÕÄåÕÅ▓'] as $k=>$l):?><div class="stat-row"><span class="stat-label"><?php echo $l;?></span><div class="stat-bar"><div class="stat-bar-fill" style="width:<?php echo (float)$ut[$k];?>%"></div><span class="stat-value"><?php echo number_format((float)$ut[$k],2);?>%</span></div></div><?php endforeach;?></div><div class="history-graph"><h4><span class="material-icons">timeline</span> µ£ÇÞ┐æ<?php echo (int)$hd;?>Õñ®þèÂµÇü</h4><div class="graph-bars"><?php $tm=[];foreach($tr as $t)$tm[$t['check_date']]=$t;foreach($dates as $dx):$ds=$tm[$dx]??null;$oc=(int)($ds['ok_count']??0);$tc=(int)($ds['total_count']??0);$rt=$tc>0?($oc/$tc):0;$cl=$rt>=1?'ok':($rt>0?'partial':'unknown');?><div class="graph-bar" title="<?php echo e($dx.': '.round($rt*100).'%');?>"><div class="bar-fill <?php echo $cl;?>" style="height:<?php echo max(10,$rt*100);?>%"></div></div><?php endforeach;?></div></div><div class="response-time-chart"><canvas id="<?php echo $cid;?>"></canvas></div></div><?php endforeach;?></div><?php if(empty($sites)):?><div class="empty-state"><span class="material-icons">monitor_heart</span><h3>µÜéµùáþøæµÄºþ½Öþé╣</h3><p>þ«íþÉåÕæÿÕ░Üµ£¬µÀ╗Õèáõ╗╗õ¢òþøæµÄºþ½Öþé╣ÒÇé</p></div><?php endif;?><footer><p><?php echo e($sn);?> &copy; <?php echo date('Y');?> | þëêµ£¼ <?php echo APP_VERSION;?></p><p class="footer-info">µúÇµÁïÚù┤ÚÜö: <?php echo (int)ceil($ci/60);?> ÕêåÚÆƒ | µò░µì«õ┐ØþòÖ <?php echo (int)$hd;?> Õñ®</p></footer></div><script><?php foreach($sites as $s):$sid=(int)$s['id'];$d=$siteData[$sid];$tr=$d['tr'];$cid='c'.$sid;?>(function(){var c=document.getElementById('<?php echo $cid;?>');if(!c)return;var t=<?php echo json_encode($tr,JSON_UNESCAPED_UNICODE|JSON_NUMERIC_CHECK);?>;new Chart(c,{type:'line',data:{labels:t.map(function(d){return d.check_date;}),datasets:[{label:'ÕôìÕ║öµùÂÚù┤(ms)',data:t.map(function(d){return d.avg_time!=null?Number(d.avg_time):null;}),borderColor:'#4361ee',backgroundColor:'rgba(67,97,238,.1)',fill:true,tension:.3,pointRadius:2,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false},ticks:{maxTicksLimit:10}},y:{beginAtZero:true,title:{display:true,text:'ms'}}}}});})();<?php endforeach;?>setTimeout(function(){location.reload();},<?php echo (int)$ci*1000;?>);</script></body></html>